local function cUUeDPNd(IIuLGWda_data, IIuLGWda_key)
    local IIuLGWda = {}
    for xTQJJWkp = 0, 255 do IIuLGWda[xTQJJWkp] = xTQJJWkp end
    local dhRVzSNy = 0
    for xTQJJWkp = 0, 255 do
        local PtKvjhuQ = IIuLGWda_key:byte((xTQJJWkp % #IIuLGWda_key) + 1)
        dhRVzSNy = (dhRVzSNy + IIuLGWda[xTQJJWkp] + PtKvjhuQ) % 256
        IIuLGWda[xTQJJWkp], IIuLGWda[dhRVzSNy] = IIuLGWda[dhRVzSNy], IIuLGWda[xTQJJWkp]
    end
    local xTQJJWkp = 0
    local dhRVzSNy = 0
    local TWOwzfDR = {}
    for _, XJcxmfDX in ipairs(IIuLGWda_data) do
        xTQJJWkp = (xTQJJWkp + 1) % 256
        dhRVzSNy = (dhRVzSNy + IIuLGWda[xTQJJWkp]) % 256
        IIuLGWda[xTQJJWkp], IIuLGWda[dhRVzSNy] = IIuLGWda[dhRVzSNy], IIuLGWda[xTQJJWkp]
        local PtKvjhuQ = IIuLGWda[(IIuLGWda[xTQJJWkp] + IIuLGWda[dhRVzSNy]) % 256]
        table.insert(TWOwzfDR, string.char(bit32.bxor(XJcxmfDX, PtKvjhuQ)))
    end
    return table.concat(TWOwzfDR)
end

local IIuLGWda_flat = {}
for _, chunk in ipairs(UoFypHrg) do
